import React, { useState, useEffect } from 'react';
import './CinemaManagement.css';

const CinemaManagement = () => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState({
    cinema_name: '',
    cinema_location: '',
    google_maps_location: '',
    contact_info: {
      phone: '',
      email: ''
    },
    ongoing_movies: {
      movie_1: { name: '', start_date: '', end_date: '', trailer_link: '' },
      movie_2: { name: '', start_date: '', end_date: '', trailer_link: '' },
      movie_3: { name: '', start_date: '', end_date: '', trailer_link: '' },
      movie_4: { name: '', start_date: '', end_date: '', trailer_link: '' }
    },
    upcoming_movies: {
      movie_1: { name: '', trailer_link: '' },
      movie_2: { name: '', trailer_link: '' }
    },
    movie_slot_pricing: {
      movie_1: { starting_price: 0, interval_price: 0, ending_price: 0 },
      movie_2: { starting_price: 0, interval_price: 0, ending_price: 0 },
      movie_3: { starting_price: 0, interval_price: 0, ending_price: 0 },
      movie_4: { starting_price: 0, interval_price: 0, ending_price: 0 }
    },
    is_active: true
  });

  const totalSteps = 7;

  const steps = [
    { id: 1, title: 'General Details', description: 'Basic cinema information' },
    { id: 2, title: 'Movie 1', description: 'First ongoing movie' },
    { id: 3, title: 'Movie 2', description: 'Second ongoing movie' },
    { id: 4, title: 'Movie 3', description: 'Third ongoing movie' },
    { id: 5, title: 'Movie 4', description: 'Fourth ongoing movie' },
    { id: 6, title: 'Upcoming Movies', description: 'Future releases' },
    { id: 7, title: 'Review & Submit', description: 'Final review' }
  ];

  const handleInputChange = (field, value) => {
    if (field.includes('.')) {
      const [parent, child] = field.split('.');
      setFormData(prev => ({
        ...prev,
        [parent]: {
          ...prev[parent],
          [child]: value
        }
      }));
    } else {
      setFormData(prev => ({
        ...prev,
        [field]: value
      }));
    }
  };

  const handleMovieChange = (movieKey, field, value) => {
    setFormData(prev => ({
      ...prev,
      ongoing_movies: {
        ...prev.ongoing_movies,
        [movieKey]: {
          ...prev.ongoing_movies[movieKey],
          [field]: value
        }
      }
    }));
  };

  const handlePricingChange = (movieKey, priceType, value) => {
    setFormData(prev => ({
      ...prev,
      movie_slot_pricing: {
        ...prev.movie_slot_pricing,
        [movieKey]: {
          ...prev.movie_slot_pricing[movieKey],
          [priceType]: parseInt(value) || 0
        }
      }
    }));
  };

  const handleUpcomingMovieChange = (movieKey, field, value) => {
    setFormData(prev => ({
      ...prev,
      upcoming_movies: {
        ...prev.upcoming_movies,
        [movieKey]: {
          ...prev.upcoming_movies[movieKey],
          [field]: value
        }
      }
    }));
  };

  const nextStep = () => {
    if (currentStep < totalSteps) {
      setCurrentStep(currentStep + 1);
    }
  };

  const prevStep = () => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  };

  const handleSubmit = async () => {
    try {
      const response = await fetch('http://localhost:5000/api/cinemas', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(formData),
      });

      const result = await response.json();

      if (result.success) {
        alert('Cinema created successfully!');
        setIsModalOpen(false);
        setCurrentStep(1);
        setFormData({
          cinema_name: '',
          cinema_location: '',
          google_maps_location: '',
          contact_info: { phone: '', email: '' },
          ongoing_movies: {
            movie_1: { name: '', start_date: '', end_date: '', trailer_link: '' },
            movie_2: { name: '', start_date: '', end_date: '', trailer_link: '' },
            movie_3: { name: '', start_date: '', end_date: '', trailer_link: '' },
            movie_4: { name: '', start_date: '', end_date: '', trailer_link: '' }
          },
          upcoming_movies: {
            movie_1: { name: '', trailer_link: '' },
            movie_2: { name: '', trailer_link: '' }
          },
          movie_slot_pricing: {
            movie_1: { starting_price: 0, interval_price: 0, ending_price: 0 },
            movie_2: { starting_price: 0, interval_price: 0, ending_price: 0 },
            movie_3: { starting_price: 0, interval_price: 0, ending_price: 0 },
            movie_4: { starting_price: 0, interval_price: 0, ending_price: 0 }
          },
          is_active: true
        });
      } else {
        alert('Error creating cinema: ' + result.message);
      }
    } catch (error) {
      console.error('Error:', error);
      alert('Error creating cinema');
    }
  };

  const renderStepContent = () => {
    switch (currentStep) {
      case 1:
        return <GeneralDetailsStep formData={formData} handleInputChange={handleInputChange} />;
      case 2:
        return <MovieStep movieKey="movie_1" movieData={formData.ongoing_movies.movie_1} formData={formData} handleMovieChange={handleMovieChange} handlePricingChange={handlePricingChange} stepNumber={1} />;
      case 3:
        return <MovieStep movieKey="movie_2" movieData={formData.ongoing_movies.movie_2} formData={formData} handleMovieChange={handleMovieChange} handlePricingChange={handlePricingChange} stepNumber={2} />;
      case 4:
        return <MovieStep movieKey="movie_3" movieData={formData.ongoing_movies.movie_3} formData={formData} handleMovieChange={handleMovieChange} handlePricingChange={handlePricingChange} stepNumber={3} />;
      case 5:
        return <MovieStep movieKey="movie_4" movieData={formData.ongoing_movies.movie_4} formData={formData} handleMovieChange={handleMovieChange} handlePricingChange={handlePricingChange} stepNumber={4} />;
      case 6:
        return <UpcomingMoviesStep formData={formData} handleUpcomingMovieChange={handleUpcomingMovieChange} />;
      case 7:
        return <ReviewStep formData={formData} />;
      default:
        return null;
    }
  };

  return (
    <div className="cinema-management">
      <div className="page-header">
        <div className="container">
          <h1>Cinema Management</h1>
          <p>Manage your cinema locations and movie schedules</p>
          <button className="cta-btn" onClick={() => setIsModalOpen(true)}>
            Add New Cinema
          </button>
        </div>
      </div>

      {isModalOpen && (
        <div className="modal-overlay">
          <div className="modal-container">
            <div className="modal-header">
              <h2>Add New Cinema</h2>
              <button className="close-btn" onClick={() => setIsModalOpen(false)}>
                ×
              </button>
            </div>

            <div className="modal-body">
              <div className="modal-layout">
                <div className="step-sidebar">
                  <div className="step-indicator">
                    {steps.map((step) => (
                      <div key={step.id} className={`step ${currentStep === step.id ? 'active' : currentStep > step.id ? 'completed' : ''}`}>
                        <div className={`step-icon step-icon-${step.icon}`}></div>
                        <div className="step-info">
                          <div className="step-title">{step.title}</div>
                          <div className="step-description">{step.description}</div>
                        </div>
                        {currentStep > step.id && <div className="step-check">✓</div>}
                      </div>
                    ))}
                  </div>
                </div>

                <div className="step-content-area">
                  <div className="step-content">
                    <div className="step-header">
                      <h3>{steps[currentStep - 1].title}</h3>
                      <p>{steps[currentStep - 1].description}</p>
                    </div>
                    <div className="step-form">
                      {renderStepContent()}
                    </div>
                  </div>

                  <div className="modal-actions">
                    <button 
                      className="btn-secondary" 
                      onClick={prevStep} 
                      disabled={currentStep === 1}
                    >
                      Previous
                    </button>
                    <div className="step-counter">
                      Step {currentStep} of {totalSteps}
                    </div>
                    {currentStep === totalSteps ? (
                      <button className="btn-primary" onClick={handleSubmit}>
                        Create Cinema
                      </button>
                    ) : (
                      <button className="btn-primary" onClick={nextStep}>
                        Next
                      </button>
                    )}
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

// General Details Step Component
const GeneralDetailsStep = ({ formData, handleInputChange }) => (
  <div className="step-content-wrapper">
    <h3>General Cinema Details</h3>
    <div className="form-grid">
      <div className="form-group">
        <label>Cinema Name *</label>
        <input
          type="text"
          value={formData.cinema_name}
          onChange={(e) => handleInputChange('cinema_name', e.target.value)}
          placeholder="Enter cinema name"
          required
        />
      </div>

      <div className="form-group">
        <label>Location *</label>
        <input
          type="text"
          value={formData.cinema_location}
          onChange={(e) => handleInputChange('cinema_location', e.target.value)}
          placeholder="Enter cinema location"
          required
        />
      </div>

      <div className="form-group full-width">
        <label>Google Maps Location</label>
        <input
          type="url"
          value={formData.google_maps_location}
          onChange={(e) => handleInputChange('google_maps_location', e.target.value)}
          placeholder="https://maps.google.com/..."
        />
      </div>

      <div className="form-group">
        <label>Phone</label>
        <input
          type="tel"
          value={formData.contact_info.phone}
